import { Component, Inject, OnInit } from '@angular/core';
import { MatDialogRef, MAT_DIALOG_DATA } from '@angular/material/dialog';
import { AuthService, User } from 'src/app/api/auth/auth.service';
import {
  AdminUsersListComponent,
} from '../admin-users-list/admin-users-list.component';

@Component({
  selector: 'app-delete-user',
  templateUrl: './delete-user.component.html',
  styleUrls: ['./delete-user.component.scss'],
})
export class DeleteUserComponent implements OnInit {
  constructor(
    public dialogRef: MatDialogRef<AdminUsersListComponent>,
    private api: AuthService,
    @Inject(MAT_DIALOG_DATA) public user: User
  ) {}

  closeDialog() {
    this.dialogRef.close();
  }
  //If The Answer is to delete the user
  //A boolean of true will be returned
  deleteUser(): void {
    this.api.deleteUser(this.user);
    this.dialogRef.close(true);
  }

  ngOnInit(): void {}
}
