import { Component, Inject, OnInit } from '@angular/core';
import {
  FormBuilder,
  FormControl,
  FormGroup,
  Validators,
} from '@angular/forms';
import { MatDialogRef, MAT_DIALOG_DATA } from '@angular/material/dialog';
import { AuthService, User } from 'src/app/api/auth/auth.service';
import { UserService } from 'src/app/api/user/user.service';
import {
  AdminUsersListComponent,
} from '../admin-users-list/admin-users-list.component';

@Component({
  selector: 'app-dialog-form',
  templateUrl: './dialog-form.component.html',
  styleUrls: ['./dialog-form.component.scss'],
})
export class DialogFormComponent implements OnInit {
  addUserForm: FormGroup;
  isCreate: boolean;

  constructor(
    public dialogRef: MatDialogRef<AdminUsersListComponent>,
    private formBuilder: FormBuilder,
    private userService: UserService,
    private authService: AuthService,
    @Inject(MAT_DIALOG_DATA) public user?: User
  ) {}

  ngOnInit(): void {
    var userData = this.user;
    this.isCreate = userData == undefined;
    this.addUserForm = this.formBuilder.group(
      this.isCreate
        ? {
            name: new FormControl('', [Validators.required]),
            email: new FormControl('', [Validators.required, Validators.email]),
            phone: new FormControl('', []),
            isEditUser: new FormControl(false, []),
          }
        : {
            id: userData.id,
            name: new FormControl(userData.name, [Validators.required]),
            email: new FormControl(userData.email, [
              Validators.required,
              Validators.email,
            ]),
            phone: new FormControl(userData.phone, []),
            isEditUser: new FormControl(userData.isEditUser, []),
          }
    );
  }

  onSubmit(): void {
    if (this.addUserForm.valid) {
      var formData = this.addUserForm.getRawValue();
      var adminUser: User = {...(formData as User), role: 'admin'};
      if (this.isCreate) {
        this.authService.createUser(adminUser).then(resp => {
          this.dialogRef.close(resp);
        });
      } else {
        this.userService.updateUser(adminUser);
        this.dialogRef.close(adminUser);
      }
    }
  }
}
